CREATE TABLE system_requirement_control_test_results
(
	id serial,
	organization_id integer NOT NULL,
	security_requirement_id integer NOT NULL,
	system_control_test_result_id integer NOT NULL,
	system_id integer NOT NULL,
	comments text DEFAULT NULL,
	assessment_weight double precision,
	CONSTRAINT pk_system_requirement_control_test_results PRIMARY KEY (id)
	, CONSTRAINT fk_system_requirement_control_test_results_to_organization FOREIGN KEY (organization_id) REFERENCES organizations (id) MATCH SIMPLE ON UPDATE CASCADE ON DELETE CASCADE
	, CONSTRAINT fk_system_requirement_control_test_results_to_system FOREIGN KEY (system_id) REFERENCES systems (id) MATCH SIMPLE ON UPDATE CASCADE ON DELETE CASCADE
	, CONSTRAINT fk_system_requirement_control_test_results_to_security_requirement FOREIGN KEY (security_requirement_id) REFERENCES security_requirements (id) MATCH SIMPLE ON UPDATE CASCADE ON DELETE CASCADE
	, CONSTRAINT fk_system_requirement_control_test_results_to_system_control_test_result FOREIGN KEY (system_control_test_result_id) REFERENCES system_control_test_results (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_system_requirement_control_test_result_to_organization ON system_requirement_control_test_results (organization_id);
CREATE INDEX i_system_requirement_control_test_result_to_system ON system_requirement_control_test_results (system_id);
CREATE INDEX i_system_requirement_control_test_results_to_security_requirement ON system_requirement_control_test_results (security_requirement_id);
CREATE INDEX i_system_requirement_control_test_results_to_system_control_test_result ON system_requirement_control_test_results (system_control_test_result_id);
